#include <unistd.h>
#include <sys/wait.h>

int main(void) {
    setbuf(stdout, NULL);

    for (int i = 0; i < 3; i++) {
        pid_t pid = fork();
        if (pid == -1) { perror("fork"); return 1; }
        if (pid == 0) {
            /* BUG: pas de _exit() — l'enfant continue la boucle */
            printf("child %d: pid=%d ppid=%d\n", i, getpid(), getppid());
            /* manque _exit(0) ici */
        }
    }

    /* BUG: le parent ne wait() pas ses enfants */
    printf("parent done\n");
    return 0;
}

