#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>

int main(void) {
    setbuf(stdout, NULL);

    for (int i = 0; i < 3; i++) {
        pid_t pid = fork();
        if (pid == -1) { perror("fork"); return 1; }
        if (pid == 0) {
            printf("child %d: pid=%d ppid=%d\n", i, getpid(), getppid());
            _exit(0);
        }
    }

    for (int i = 0; i < 3; i++)
        wait(NULL);

    printf("parent done\n");
    return 0;
}

